@module dataStore  src=dataStore.lua  loc=202  sha=a17a7a7  mode=chunk  self=ds
@deps ps

# Invariants & contracts
  @invariant  per-key document storage over pextStore; each name lives at one scope (no tier merge)
  @invariant  registry is sole truth for valid names; unknown names raise on every entry point
  @invariant  owns its cache: deep-clone out and in; callers never alias ds state
  @invariant  take/track caches drop on contextChanged; project/global are context-free
  @contract  take/track scopes are per-key P_EXT blobs (ctm_data.<name>); global is a disk file

# Imports
  @require util = 'util'  @ 10
      @reaper  none directly; storage + undo watcher are delegated to pextStore

# Private state
  @state ps = assert(deps and deps.ps, 'dataStore requires a pextStore ...  @ 13
  @state registry = {  @ 20
  @state GLOBAL_SLOT = 'data'  @ 41
  @state cache = { take = nil, track = nil, project = nil, global = nil }  @ 64
  @state ds = {}  @ 105
  @state fire = util.installHooks(ds)  @ 106
  @state PROJECT_PLAIN = { guardedTrack = true }  @ 119
  @state undoable = {}  @ 125
  @state watched = {}  @ 133

# Private functions
  @fn print(...)  @ 15
  -- REGISTRY
  @fn slotFor(scope, name)  @ 45-49
      -- take/track keep one P_EXT slot per name for write isolation + per-key undo
      -- baselines; project reuses the engine's projext section with slot = name.
  @fn checkName(name)  @ 51-53
  @fn copy(v)  @ 55-58
  -- CACHE
  @fn loadScope(scope)  @ 68-81
      -- Tolerant: a stale name in the global file (post-rename) is dropped, not raised
      -- (mirrors cm's pruneUnknown). Per-key blobs can't accrue unknowns -- skip them.
  @fn ensureScope(scope)  @ 83-85
  @fn persist(scope, name, value)  @ 89-101
      -- util.REMOVE clears the slot. take/track writes are loud if unbound (document
      -- data isn't recomputable, unlike configManager's silent take-tier skip).
  -- PUBLIC INTERFACE
  -- Watcher
  @fn projectUndoable(name)  @ 121-123

# Public API (ds:*)
  -- Reading
  @api ds:get(name)  @ 152-157
      @contract  returns deep copy at name's scope; nil if absent; raises on unknown name
  @api ds:getAt(handle, name)  @ 160-164
      -- Foreign-handle read: bypasses bound context; scope (take/track) from the registry.
  -- Writing
  @api ds:assign(name, value)  @ 169-182
      @contract  writes one key at its registry scope; REMOVE deletes; fires dataChanged { scope, name }
  @api ds:delete(name)  @ 184
  @api ds:assignAt(handle, name, value)  @ 188-200
      -- Foreign-handle write; util.REMOVE deletes. Refreshes the cache + signals only for
      -- the bound handle, so a write aimed at another take/track doesn't disturb the view.

# Signals emitted (via util.installHooks)
  @emits dataChanged   -- { scope, name }   @ 145 assign:181 assignAt:198

# Uses (outbound edges)
  @use call    ps.assign  @ persist:91,93,96,99
  @use call    ps.assignAt  @ assignAt:191
  @use call    ps.boundTake  @ persist:98 assignAt:192
  @use call    ps.boundTrack  @ persist:95 assignAt:193
  @use call    ps.get  @ loadScope:71,77 143
  @use call    ps.getAt  @ getAt:163
  @use call    ps.watch  @ 140
  @use call    util.deepClone  @ copy:56
  @use call    util.installHooks  @ 106
  @use call    util.print  @ print:15
  @use require util  @ 10
  @use sub     ps:contextChanged  @ 110
